      "issues": [
        {
          "title": "valve-1 的压降参数符号与节流方向冲突",
          "details": "诊断明确指出 valve-1 的 pressure_drop_kpa 为负值，且与预期节流方向冲突。该问题直接落在当前选中的阀门对象上，适合提出局部、可审查的参数修正候选。",
          "citations": [
            "diag-1",
            "flowdoc-unit-1",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "将 valve-1 的压降改为非负占位值",
          "target": {
            "type": "unit",
            "id": "valve-1"
          },
          "rationale": "当前唯一直接落在所选对象上的错误是负压降。将 pressure_drop_kpa 从负值修正为非负值可消除该局部符号冲突，同时避免基于不足证据去修改下游设备、流股规格或整体拓扑。由于请求仅提供了“负值无效”的直接证据，具体新值宜采用占位方式待人工确认。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "units[valve-1].config.pressure_drop_kpa",
                "expected_type": "number",
                "constraints": {
                  "minimum": 0,
                  "exclusive_minimum": true
                },
                "suggested_basis": "replace invalid negative pressure drop with a small positive throttling value consistent with intended flow direction"
              }
            ]
          },
          "risk_level": "medium",
